package com.google.gson.internal.reflect;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import java.lang.reflect.Constructor;
import java.lang.reflect.Modifier;
import org.junit.jupiter.api.Test;

class ReflectionHelperTest {

  @Test
  void testConstructorToString_noParameters() throws Exception {
    class TestClassNoParams {
      public TestClassNoParams() {}
    }
    Constructor<?> constructor = TestClassNoParams.class.getConstructor();

    String result = ReflectionHelper.constructorToString(constructor);

    assertEquals("com.google.gson.internal.reflect.ReflectionHelperTest$1TestClassNoParams()", result);
  }

  @Test
  void testConstructorToString_withParameters() throws Exception {
    class TestClassWithParams {
      public TestClassWithParams(int a, String b) {}
    }
    Constructor<?> constructor = TestClassWithParams.class.getConstructor(int.class, String.class);

    String result = ReflectionHelper.constructorToString(constructor);

    assertEquals(
        "com.google.gson.internal.reflect.ReflectionHelperTest$2TestClassWithParams(int,java.lang.String)",
        result);
  }

  @Test
  void testConstructorToString_withMockedConstructor() throws Exception {
    Constructor<?> constructor = mock(Constructor.class);
    Class<?> declaringClass = mock(Class.class);
    when(constructor.getDeclaringClass()).thenReturn(declaringClass);
    when(declaringClass.getName()).thenReturn("mocked.ClassName");
    when(constructor.getParameterTypes()).thenReturn(new Class<?>[] {String.class, int.class});
    when(constructor.getModifiers()).thenReturn(Modifier.PUBLIC);

    // Use reflection to invoke private appendExecutableParameters to append parameter types manually
    // But constructorToString already calls appendExecutableParameters internally

    String result = ReflectionHelper.constructorToString(constructor);

    assertEquals("mocked.ClassName(java.lang.String,int)", result);
  }
}
